INSERT INTO `beer_entry_extra_field` VALUES (1,1,'specialIngredients','?????????','????'),(2,2,'specialIngredients','增味原料或特殊工艺','none'),(3,63,'specialIngredients','增味原料或特殊工艺','爆炸发酵'),(4,41001,'specialIngredients','增味原料或特殊工艺','测试酒款：清爽米香、轻麦芽、低苦度。'),(5,41002,'specialIngredients','增味原料或特殊工艺','测试酒款：淡麦芽、草本酒花、干净发酵。'),(6,41003,'specialIngredients','增味原料或特殊工艺','测试酒款：面包麦香、柔和甜感、清亮酒体。'),(7,41004,'specialIngredients','增味原料或特殊工艺','测试酒款：低酯香、轻麦芽、适饮性高。'),(8,41005,'specialIngredients','增味原料或特殊工艺','测试酒款：饼干麦芽、细腻酒花、余味干爽。'),(9,41006,'specialIngredients','增味原料或特殊工艺','测试酒款：烘烤麦芽、轻焦糖、低酯香。'),(10,41007,'specialIngredients','增味原料或特殊工艺','测试酒款：可可感、面包皮、圆润酒体。'),(11,41008,'specialIngredients','增味原料或特殊工艺','测试酒款：轻烘烤、深色麦芽、清爽尾韵。'),(12,41009,'specialIngredients','增味原料或特殊工艺','测试酒款：坚果、焦糖、烘烤麦芽。'),(13,41010,'specialIngredients','增味原料或特殊工艺','测试酒款：轻巧咖啡、焦糖、干净发酵。'),(14,41011,'specialIngredients','增味原料或特殊工艺','马达加斯加香草奶油'),(15,41013,'specialIngredients','增味原料或特殊工艺','焦糖与香草缠绵'),(16,41014,'specialIngredients','增味原料或特殊工艺','低温长时发酵'),(17,41015,'specialIngredients','增味原料或特殊工艺','软水糖化与草本型酒花'),(18,41016,'specialIngredients','增味原料或特殊工艺','深色麦芽与低温熟成'),(21,41020,'specialIngredients','增味原料','芫荽籽和海盐'),(22,41021,'specialIngredients','增味原料','茶水'),(23,41022,'specialIngredients','增味原料','112'),(24,41023,'specialIngredients','增味原料','桶陈'),(25,41024,'specialIngredients','增味原料','烘烤麦芽'),(26,41025,'specialIngredients','增味原料','茶叶'),(27,41026,'specialIngredients','增味原料','西瓜');
