DROP TABLE IF EXISTS `competition`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `competition` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `code` varchar(64) NOT NULL,
  `name` varchar(128) NOT NULL,
  `competition_date` date NOT NULL,
  `registration_start` datetime DEFAULT NULL,
  `registration_deadline` datetime NOT NULL,
  `status` varchar(32) NOT NULL,
  `entry_fee` decimal(10,2) NOT NULL DEFAULT '0.00',
  `early_bird_fee` decimal(10,2) DEFAULT NULL,
  `early_bird_deadline` datetime DEFAULT NULL,
  `description` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `rules_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `style_library_version` varchar(64) NOT NULL DEFAULT 'BJCP_2021_CN',
  `delivery_method` varchar(32) NOT NULL DEFAULT 'BOTH' COMMENT 'delivery method: EXPRESS/ONSITE/BOTH',
  `sample_arrival_start` datetime DEFAULT NULL COMMENT 'sample arrival start',
  `sample_arrival_deadline` datetime DEFAULT NULL COMMENT 'sample arrival deadline',
  `sample_quantity_note` varchar(255) DEFAULT NULL COMMENT 'sample quantity note',
  `delivery_recipient` varchar(64) DEFAULT NULL COMMENT 'delivery recipient',
  `delivery_phone` varchar(64) DEFAULT NULL COMMENT 'delivery phone',
  `delivery_address` varchar(500) DEFAULT NULL COMMENT 'delivery address',
  `delivery_note` varchar(1000) DEFAULT NULL COMMENT 'delivery note',
  `logistics_visibility` varchar(32) NOT NULL DEFAULT 'PAYMENT_CONFIRMED' COMMENT 'logistics visibility: PUBLIC/LOGIN_REQUIRED/PAYMENT_CONFIRMED',
  `deleted_flag` tinyint NOT NULL DEFAULT '0',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_competition_code` (`code`),
  KEY `idx_competition_status_registration_deadline` (`status`,`registration_deadline`)
) ENGINE=InnoDB AUTO_INCREMENT=150 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='??';
/*!40101 SET character_set_client = @saved_cs_client */;

