INSERT INTO `score_record` VALUES (1,4,41001,21,23,'PROFESSIONAL','[{\"key\": \"aroma\", \"label\": \"香气\", \"score\": 3, \"maxScore\": 12, \"notePrompt\": null}, {\"key\": \"appearance\", \"label\": \"外观\", \"score\": 1, \"maxScore\": 3, \"notePrompt\": null}, {\"key\": \"flavor\", \"label\": \"味道\", \"score\": 10, \"maxScore\": 20, \"notePrompt\": null}, {\"key\": \"mouthfeel\", \"label\": \"口感\", \"score\": 2, \"maxScore\": 5, \"notePrompt\": null}, {\"key\": \"overall\", \"label\": \"整体印象\", \"score\": 5, \"maxScore\": 10, \"notePrompt\": null}]',21.00,'整体印象：11111111111111111111111111111111111111111111',0,0,NULL,'2026-06-04 22:11:26','2026-06-04 22:11:26'),(6,4,41001,20,22,'PROFESSIONAL','[{\"key\": \"aroma\", \"label\": \"香气\", \"score\": 6, \"maxScore\": 12, \"notePrompt\": null}, {\"key\": \"appearance\", \"label\": \"外观\", \"score\": 2, \"maxScore\": 3, \"notePrompt\": null}, {\"key\": \"flavor\", \"label\": \"味道\", \"score\": 9, \"maxScore\": 20, \"notePrompt\": null}, {\"key\": \"mouthfeel\", \"label\": \"口感\", \"score\": 2, \"maxScore\": 5, \"notePrompt\": null}, {\"key\": \"overall\", \"label\": \"整体印象\", \"score\": 5, \"maxScore\": 10, \"notePrompt\": null}]',24.00,'香气：1233333333\n外观：21111111\n味道：2222222\n口感：11111111\n整体印象：2222222222',0,0,NULL,'2026-06-04 22:57:29','2026-06-04 22:57:29'),(7,4,63,20,22,'PROFESSIONAL','[{\"key\": \"aroma\", \"note\": \"酒花香气清晰，有柑橘和热带水果调性，强度适中但复杂度不足。\", \"label\": \"香气\", \"score\": 6, \"maxScore\": 12}, {\"key\": \"appearance\", \"note\": \"颜色符合风格预期，浑浊度自然，泡沫挂杯表现中等。\", \"label\": \"外观\", \"score\": 2, \"maxScore\": 3}, {\"key\": \"flavor\", \"note\": \"前段果香突出，麦芽甜感支撑尚可，苦味平衡度良好但收口稍短。\", \"label\": \"味道\", \"score\": 12, \"maxScore\": 20}, {\"key\": \"mouthfeel\", \"note\": \"碳酸感适中，酒体厚度偏轻，温度升高后口感更圆润。\", \"label\": \"口感\", \"score\": 3, \"maxScore\": 5}, {\"key\": \"overall\", \"note\": \"风格方向明确，缺陷控制较好，若增强尾段层次会更有竞争力。\", \"label\": \"整体印象\", \"score\": 6, \"maxScore\": 10}]',29.00,'香气：酒花香气清晰，有柑橘和热带水果调性，强度适中但复杂度不足。\n外观：颜色符合风格预期，浑浊度自然，泡沫挂杯表现中等。\n味道：前段果香突出，麦芽甜感支撑尚可，苦味平衡度良好但收口稍短。\n口感：碳酸感适中，酒体厚度偏轻，温度升高后口感更圆润。\n整体印象：风格方向明确，缺陷控制较好，若增强尾段层次会更有竞争力。',0,0,NULL,'2026-06-04 22:59:13','2026-06-06 12:09:11'),(8,4,41002,20,22,'PROFESSIONAL','[{\"key\": \"aroma\", \"label\": \"香气\", \"score\": 6, \"maxScore\": 12, \"notePrompt\": null}, {\"key\": \"appearance\", \"label\": \"外观\", \"score\": 2, \"maxScore\": 3, \"notePrompt\": null}, {\"key\": \"flavor\", \"label\": \"味道\", \"score\": 11, \"maxScore\": 20, \"notePrompt\": null}, {\"key\": \"mouthfeel\", \"label\": \"口感\", \"score\": 3, \"maxScore\": 5, \"notePrompt\": null}, {\"key\": \"overall\", \"label\": \"整体印象\", \"score\": 7, \"maxScore\": 10, \"notePrompt\": null}]',29.00,'香气：1111111111111111111111111111111111111',0,0,NULL,'2026-06-04 22:59:27','2026-06-04 22:59:27'),(9,4,41003,20,22,'PROFESSIONAL','[{\"key\": \"aroma\", \"label\": \"香气\", \"score\": 6, \"maxScore\": 12, \"notePrompt\": null}, {\"key\": \"appearance\", \"label\": \"外观\", \"score\": 2, \"maxScore\": 3, \"notePrompt\": null}, {\"key\": \"flavor\", \"label\": \"味道\", \"score\": 13, \"maxScore\": 20, \"notePrompt\": null}, {\"key\": \"mouthfeel\", \"label\": \"口感\", \"score\": 3, \"maxScore\": 5, \"notePrompt\": null}, {\"key\": \"overall\", \"label\": \"整体印象\", \"score\": 7, \"maxScore\": 10, \"notePrompt\": null}]',31.00,'整体印象：1111111111111111111111111111111111111111111',0,0,NULL,'2026-06-04 22:59:40','2026-06-04 22:59:40'),(10,4,41001,19,21,'CROSS','[{\"key\": \"appearance\", \"label\": \"第一印象\", \"score\": 6, \"maxScore\": 10, \"notePrompt\": null}, {\"key\": \"drinkability\", \"label\": \"易饮度\", \"score\": 13, \"maxScore\": 20, \"notePrompt\": null}, {\"key\": \"overall\", \"label\": \"整体喜好\", \"score\": 13, \"maxScore\": 20, \"notePrompt\": null}]',32.00,'整体喜好：111111111111111111111111111111111111111111111111111111111111111111111111111',0,0,NULL,'2026-06-04 23:00:16','2026-06-04 23:00:16'),(11,4,41002,19,21,'CROSS','[{\"key\": \"appearance\", \"label\": \"第一印象\", \"score\": 6, \"max